ee:message.ee:set-payload:
%dw 2.0
output application/xml
ns env http://schemas.xmlsoap.org/soap/envelope/
ns sf urn:partner.soap.sforce.com
---
env#Envelope: {
  env#Header: {},
  env#Body: {
    sf#login: {
      sf#username: p('sf.username'),
      sf#password: p('sf.password') ++ p('sf.token')
    }
  }
}
